SELECT party_name, party_type, party_contact
FROM contract_parties
WHERE contract_id = 1;

SELECT contract_id, contract_name, contract_type
FROM contracts
WHERE contract_type = 'NDA';

SELECT MAX(contract_id) AS "Highest contract_id", 
       MIN(contract_id) AS "Lowest contract_id"
FROM contracts;

SELECT users.user_name
FROM users
JOIN contracts ON users.user_id = contracts.created_by;

SELECT contract_id, COUNT(*) AS revision_count
FROM contract_revisions
GROUP BY contract_id;

SELECT entity_text
FROM contract_entities
WHERE entity_id = 0;

SELECT AVG(entity_count) AS average_entities_per_contract
FROM (
    SELECT contract_id, COUNT(*) AS entity_count
    FROM contract_entities
    GROUP BY contract_id
);

SELECT u.user_name
FROM users u
WHERE u.user_id IN (
    SELECT c.created_by
    FROM contracts c
) AND u.user_id NOT IN (
    SELECT ua.user_id
    FROM user_access ua
);

SELECT object_name, object_description
FROM contract_objects
WHERE contract_id = 1;
